from openai import OpenAI

client = OpenAI(api_key='YOUR_API_KEY')

# Basic chat completion
response = client.chat.completions.create(
    model='gpt-4o',
    messages=[
        {'role': 'system', 'content': 'You are a helpful software assistant.'},
        {'role': 'user', 'content': 'Explain what a REST API is in 2 sentences.'}
    ]
)
print(response.choices[0].message.content)

# With function calling
tools = [{
    'type': 'function',
    'function': {
        'name': 'get_weather',
        'description': 'Get current weather for a city',
        'parameters': {'type': 'object', 'properties': {'city': {'type': 'string'}}}
    }
}]
response = client.chat.completions.create(model='gpt-4o', messages=[{'role':'user','content':'Weather in Toronto?'}], tools=tools)
